mapper.sql:
o.is_deleted = 0

    AND o.order_status = #{q.orderStatus}
    AND o.order_status >= 4

AND o.order_date >= #{q.dateFrom}
AND o.order_date <= #{q.dateTo}
AND o.customer_uuid = #{q.customerUuid}
AND o.settle_type = #{q.settleType}
AND o.is_invoice = #{q.isInvoice}

    AND EXISTS (
        SELECT 1
        FROM biz_original_roll rf
        WHERE rf.order_uuid = o.uuid
          AND rf.is_deleted = 0
          AND rf.paper_name LIKE CONCAT('%', #{q.paperName}, '%')
    )


    AND EXISTS (
        SELECT 1
        FROM biz_original_roll rf
        WHERE rf.order_uuid = o.uuid
          AND rf.is_deleted = 0
          AND rf.main_step_type = #{q.mainStepType}
    )


    AND EXISTS (
        SELECT 1
        FROM biz_original_roll rf
        WHERE rf.order_uuid = o.uuid
          AND rf.is_deleted = 0
          AND rf.process_mode = #{q.processMode}
    )


    AND EXISTS (
        SELECT 1
        FROM biz_original_roll rf
        WHERE rf.order_uuid = o.uuid
          AND rf.is_deleted = 0
          AND rf.machine_uuid = #{q.machineUuid}
    )

mapper.select:
SELECT DATE_FORMAT(o.order_date, '%Y-%m') AS month, COUNT(*) AS orderCount, COALESCE(SUM(orig.originalWeight), 0) / 1000 AS totalTon, COALESCE(SUM(step.totalKnife), 0) AS totalKnife, COALESCE(SUM(COALESCE(settle.billedAmount, o.total_amount, 0)), 0) AS totalAmount, COALESCE(SUM(fin.finishWeight), 0) AS totalFinishWeight FROM biz_process_order o LEFT JOIN ( SELECT order_uuid, SUM(COALESCE(actual_weight, total_weight, roll_weight, 0)) AS originalWeight FROM biz_original_roll WHERE is_deleted = 0 GROUP BY order_uuid ) orig ON orig.order_uuid = o.uuid LEFT JOIN ( SELECT order_uuid, SUM(COALESCE(actual_weight, estimate_weight, 0)) AS finishWeight FROM biz_finish_roll WHERE is_deleted = 0 AND COALESCE(is_spare, 0) = 0 AND COALESCE(roll_no_status, 1) != 3 GROUP BY order_uuid ) fin ON fin.order_uuid = o.uuid LEFT JOIN ( SELECT order_uuid, SUM(COALESCE(knife_count, 0)) AS totalKnife FROM biz_process_step WHERE is_deleted = 0 AND step_type = 1 GROUP BY order_uuid ) step ON step.order_uuid = o.uuid LEFT JOIN (
) settle ON settle.order_uuid = o.uuid
GROUP BY DATE_FORMAT(o.order_date, '%Y-%m') ORDER BY month

SELECT o.customer_uuid AS customerUuid, o.customer_name AS customerName, COUNT(*) AS orderCount, COALESCE(SUM(orig.originalWeight), 0) / 1000 AS totalTon, COALESCE(SUM(step.totalKnife), 0) AS totalKnife, COALESCE(SUM(COALESCE(settle.billedAmount, o.total_amount, 0)), 0) AS totalAmount FROM biz_process_order o LEFT JOIN ( SELECT order_uuid, SUM(COALESCE(actual_weight, total_weight, roll_weight, 0)) AS originalWeight FROM biz_original_roll WHERE is_deleted = 0 GROUP BY order_uuid ) orig ON orig.order_uuid = o.uuid LEFT JOIN ( SELECT order_uuid, SUM(COALESCE(knife_count, 0)) AS totalKnife FROM biz_process_step WHERE is_deleted = 0 AND step_type = 1 GROUP BY order_uuid ) step ON step.order_uuid = o.uuid LEFT JOIN (
) settle ON settle.order_uuid = o.uuid
GROUP BY o.customer_uuid, o.customer_name ORDER BY totalAmount DESC
